{% extends 'dashboard/base_dashboard.html' %}
{% load static %}

{% block title %}Invest in {{ plan.name }}{% endblock %}

{% block extra_css %}
<style>
    .invest-header {
        text-align: center;
        margin-bottom: 40px;
    }
    .invest-header h1 {
        font-size: 2.5rem;
        background: linear-gradient(to right, var(--gold), #ffce54);
        -webkit-background-clip: text;
        -webkit-text-fill-color: transparent;
    }
    .invest-grid {
        display: grid;
        grid-template-columns: 1fr 400px;
        gap: 30px;
    }
    @media (max-width: 991px) {
        .invest-grid { grid-template-columns: 1fr; }
    }
    .glass-card {
        background: rgba(255, 255, 255, 0.03);
        border: 1px solid rgba(255, 255, 255, 0.1);
        border-radius: 24px;
        padding: 35px;
        backdrop-filter: blur(15px);
    }
    .highlight-text { color: var(--gold); font-weight: 700; }
    .roi-badge {
        display: inline-block;
        padding: 8px 16px;
        background: rgba(255, 215, 0, 0.1);
        border-radius: 12px;
        color: var(--gold);
        font-weight: 600;
        margin-bottom: 20px;
    }
</style>
{% endblock %}

{% block content %}
<div class="invest-header">
    <h1>Invest in {{ plan.name }}</h1>
    <p class="text-secondary">Maximize your wealth with our premium strategy</p>
</div>

<div class="invest-grid">
    <div class="glass-card">
        <form method="POST" id="investForm">
            {% csrf_token %}
            <div class="form-group mb-4">
                <label class="form-label text-uppercase small text-muted">Amount to Invest ($)</label>
                <input type="number" name="amount" id="investAmount" class="form-input form-control-lg" 
                       min="{{ plan.min_amount }}" max="{{ plan.max_amount }}" step="100" required oninput="syncInputs(this.value)">

                <input type="range" id="investRange" class="input-range mt-3"
                       min="{{ plan.min_amount }}" max="{{ plan.max_amount }}" step="100" value="{{ plan.min_amount }}"
                       oninput="syncInputs(this.value)">
            </div>
            <button type="submit" class="btn-gold btn-lg w-100 mt-4 rounded-pill">Execute Investment</button>
        </form>
    </div>

    <div class="glass-card">
        <div class="roi-badge">{{ plan.daily_roi }}% Daily ROI</div>
        <h4 class="mb-4">Calculation Summary</h4>
        <div class="d-flex justify-content-between mb-3">
            <span class="text-muted">Investment:</span> <span id="calcAmount" class="fw-bold">$0</span>
        </div>
        <div class="d-flex justify-content-between mb-3">
            <span class="text-muted">Total Profit:</span> <span id="calcProfit" class="text-success fw-bold">$0</span>
        </div>
        <div class="d-flex justify-content-between pt-3 border-top border-secondary">
            <span class="text-muted">Total Returns:</span> <span id="calcTotal" class="text-light fw-bold fs-4">$0</span>
        </div>
    </div>
</div>

<script>
    const dailyRoi = {{ plan.daily_roi }};
    const duration = {{ plan.duration_days }};

    function syncInputs(val) {
        document.getElementById('investAmount').value = val;
        document.getElementById('investRange').value = val;
        const amt = parseFloat(val) || 0;
        const profit = (amt * dailyRoi / 100) * duration;
        document.getElementById('calcAmount').textContent = '$' + amt.toLocaleString();
        document.getElementById('calcProfit').textContent = '$' + profit.toLocaleString(undefined, {minimumFractionDigits: 2});
        document.getElementById('calcTotal').textContent = '$' + (amt + profit).toLocaleString(undefined, {minimumFractionDigits: 2});
    }
    syncInputs({{ plan.min_amount }});
</script>
{% endblock %}

