                    </div>
                    <div class="stat-label">Pending Withdrawal</div>
                    <div class="stat-value">${{ pending_withdrawals|floatformat:2 }}</div>
                    <div class="stat-change">
                        <i class="fas fa-clock me-1"></i>In progress
                    </div>
                </div>
            </div>
        </div>

        <div class="row mb-4">
            <div class="col-lg-8">
                <!-- Asset Breakdown Chart -->
                <div class="portfolio-card">
                    <div class="portfolio-header">
                        <h3><i class="fas fa-pie-chart me-2" style="color: var(--emerald);"></i>Asset Breakdown</h3>
                    </div>
                    <div class="chart-container">
                        <canvas id="assetChart"></canvas>
                    </div>
                </div>

                <!-- Recent Transactions -->
                <div class="portfolio-card">
                    <div class="portfolio-header">
                        <h3><i class="fas fa-exchange-alt me-2" style="color: var(--emerald);"></i>Recent Transactions</h3>
                        <a href="{% url 'dashboard:transactions' %}" class="btn btn-sm btn-outline-primary">View All</a>
                    </div>

                    {% if recent_deposits or recent_withdrawals %}
                        {% for deposit in recent_deposits|slice:":5" %}
                            <div class="transaction-item">
                                <div style="display: flex; align-items: center;">
                                    <div class="transaction-icon deposit">
                                        <i class="fas fa-arrow-down"></i>
                                    </div>
                                    <div class="transaction-details">
                                        <div class="transaction-type">Deposit</div>
                                        <div class="transaction-date">{{ deposit.created_at|date:"M d, Y H:i" }}</div>
                                    </div>
                                </div>
                                <div class="transaction-amount positive">
                                    +${{ deposit.amount|floatformat:2 }}
                                </div>
                            </div>
                        {% endfor %}

                        {% for withdrawal in recent_withdrawals|slice:":5" %}
                            <div class="transaction-item">
                                <div style="display: flex; align-items: center;">
                                    <div class="transaction-icon withdrawal">
                                        <i class="fas fa-arrow-up"></i>
                                    </div>
                                    <div class="transaction-details">
                                        <div class="transaction-type">Withdrawal</div>
                                        <div class="transaction-date">{{ withdrawal.created_at|date:"M d, Y H:i" }}</div>
                                    </div>
                                </div>
                                <div class="transaction-amount negative">
                                    -${{ withdrawal.amount|floatformat:2 }}
                                </div>
                            </div>
                        {% endfor %}
                    {% else %}
                        <p style="text-align: center; color: #999; padding: 20px;">No transactions yet</p>
                    {% endif %}
                </div>
            </div>

            <!-- Quick Stats & Notifications Sidebar -->
            <div class="col-lg-4">
                <!-- Referral Earnings -->
                <div class="stat-card">
                    <div class="stat-icon" style="background: rgba(255, 215, 0, 0.1); color: var(--gold);">
                        <i class="fas fa-gift"></i>
                    </div>
                    <div class="stat-label">Referral Earnings</div>
                    <div class="stat-value">${{ referral_earnings|floatformat:2 }}</div>
                    <a href="{% url 'accounts:referrals' %}" class="btn btn-sm btn-primary mt-3 w-100">
                        <i class="fas fa-share-alt me-2"></i>Share & Earn
                    </a>
                </div>

                <!-- Notifications -->
                <div class="portfolio-card">
                    <h5 class="mb-3"><i class="fas fa-bell me-2" style="color: var(--emerald);"></i>Recent Alerts</h5>
                    {% if notifications %}
                        {% for notif in notifications|slice:":5" %}
                            <div class="notification-item {% if notif.type == 'warning' %}warning{% elif notif.type == 'danger' %}danger{% endif %}">
                                <div class="notification-title">{{ notif.title }}</div>
                                <div class="notification-text">{{ notif.message|truncatewords:10 }}</div>
                                <div class="notification-time">{{ notif.created_at|timesince }} ago</div>
                            </div>
                        {% endfor %}
                    {% else %}
                        <p style="color: #999; text-align: center;">No new notifications</p>
                    {% endif %}
                </div>

                <!-- Quick Actions -->
                <div class="portfolio-card">
                    <h5 class="mb-3"><i class="fas fa-bolt me-2" style="color: var(--gold);"></i>Quick Actions</h5>
                    <div class="quick-actions">
                        <a href="{% url 'investments:deposit' %}" class="action-btn">
                            <i class="fas fa-money-bill-wave"></i>
                            <span>Add Funds</span>
                        </a>
                        <a href="{% url 'investments:withdraw' %}" class="action-btn">
                            <i class="fas fa-sign-out-alt"></i>
                            <span>Withdraw</span>
                        </a>
                        <a href="{% url 'investments:plans' %}" class="action-btn">
                            <i class="fas fa-plus-circle"></i>
                            <span>Invest</span>
                        </a>
                        <a href="{% url 'investments:cards' %}" class="action-btn">
                            <i class="fas fa-credit-card"></i>
                            <span>Cards</span>
                        </a>
                        <a href="{% url 'investments:loans' %}" class="action-btn">
                            <i class="fas fa-hand-holding-usd"></i>
                            <span>Loans</span>
                        </a>
                        <a href="{% url 'investments:agent' %}" class="action-btn">
                            <i class="fas fa-user-tie"></i>
                            <span>Agent</span>
                        </a>
                    </div>
                </div>
            </div>
        </div>

        <!-- Investment Opportunities Carousel -->
        <div class="portfolio-card">
            <div class="portfolio-header">
                <h3><i class="fas fa-star me-2" style="color: var(--emerald);"></i>Featured Investment Plans</h3>
            </div>

            <div class="carousel-container">
                <div style="display: grid; grid-template-columns: repeat(auto-fit, minmax(200px, 1fr)); gap: 20px;">
                    {% for plan in featured_plans %}
                        <div class="investment-plan-card">
                            <div class="investment-plan-icon">
                                <i class="fas fa-{{ plan.icon }}"></i>
                            </div>
                            <div class="investment-plan-name">{{ plan.name }}</div>
                            <div class="investment-plan-roi">{{ plan.daily_roi }}%</div>
                            <div class="investment-plan-duration">
                                <i class="fas fa-clock me-1"></i>Daily for {{ plan.duration_days }} days
                            </div>
                            <div style="margin-top: 15px;">
                                <small style="color: #999;">Min: ${{ plan.min_amount|floatformat:0 }} - Max: ${{ plan.max_amount|floatformat:0 }}</small>
                            </div>
                            <button class="btn btn-primary btn-sm mt-3 w-100">Buy Shares</button>
                        </div>
                    {% endfor %}
                </div>
            </div>
        </div>

        <!-- Active Investments -->
        {% if active_investments %}
            <div class="portfolio-card">
                <div class="portfolio-header">
                    <h3><i class="fas fa-briefcase me-2" style="color: var(--emerald);"></i>Active Investments</h3>
                    <span class="status-badge status-active">{{ active_count }} Active</span>
                </div>

                <div style="overflow-x: auto;">
                    <table class="table table-hover mb-0">
                        <thead style="background: #f8f9fa;">
                            <tr>
                                <th>Plan</th>
                                <th>Amount</th>
                                <th>Expected Profit</th>
                                <th>Status</th>
                                <th>End Date</th>
                            </tr>
                        </thead>
                        <tbody>
                            {% for investment in active_investments %}
                                <tr>
                                    <td>
                                        <strong>{{ investment.plan.name }}</strong>
                                    </td>
                                    <td>${{ investment.amount|floatformat:2 }}</td>
                                    <td>
                                        <span style="color: #28a745; font-weight: 600;">
                                            +${{ investment.expected_profit|floatformat:2 }}
                                        </span>
                                    </td>
                                    <td>
                                        <span class="status-badge status-active">
                                            <i class="fas fa-check-circle me-1"></i>Active
                                        </span>
                                    </td>
                                    <td>{{ investment.end_date|date:"M d, Y" }}</td>
                                </tr>
                            {% endfor %}
                        </tbody>
                    </table>
                </div>
            </div>
        {% endif %}
    </div>

    <!-- Footer -->
    <footer style="background: var(--dark-navy); color: white; padding: 30px 0; margin-top: 60px;">
        <div class="container-lg">
            <div class="row">
                <div class="col-md-4 mb-4">
                    <h5><i class="fas fa-crown me-2"></i>Elite Wealth Capital</h5>
                    <p style="opacity: 0.8;">Your trusted investment platform for secure wealth growth.</p>
                </div>
                <div class="col-md-4 mb-4">
                    <h5>Quick Links</h5>
                    <ul style="list-style: none; padding: 0;">
                        <li><a href="{% url 'dashboard:about' %}" style="color: rgba(255, 255, 255, 0.8);">About Us</a></li>
                        <li><a href="{% url 'dashboard:faq' %}" style="color: rgba(255, 255, 255, 0.8);">FAQ</a></li>
                        <li><a href="{% url 'dashboard:contact' %}" style="color: rgba(255, 255, 255, 0.8);">Contact</a></li>
                    </ul>
                </div>
                <div class="col-md-4 mb-4">
                    <h5>Security</h5>
                    <ul style="list-style: none; padding: 0;">
                        <li><a href="{% url 'dashboard:privacy_policy' %}" style="color: rgba(255, 255, 255, 0.8);">Privacy Policy</a></li>
                        <li><a href="{% url 'dashboard:terms' %}" style="color: rgba(255, 255, 255, 0.8);">Terms & Conditions</a></li>
                    </ul>
                </div>
            </div>
            <hr style="opacity: 0.2;">
            <p style="text-align: center; opacity: 0.7; margin: 0;">© 2024 Elite Wealth Capital. All rights reserved.</p>
        </div>
    </footer>

    <!-- Scripts -->
    <script src="https://cdn.jsdelivr.net/npm/bootstrap@5.3.0/dist/js/bootstrap.bundle.min.js"></script>
    <script>
        // Asset Breakdown Chart
        const ctx = document.getElementById('assetChart');
        if (ctx) {
            const assetData = {
                labels: [
                    {% for item in investments_by_type %}'{{ item.plan__name }}'{% if not forloop.last %}, {% endif %}{% endfor %}
                ],
                datasets: [{
                    data: [
                        {% for item in investments_by_type %}{{ item.total|floatformat:2 }}{% if not forloop.last %}, {% endif %}{% endfor %}
                    ],
                    backgroundColor: [
                        'rgba(10, 31, 68, 0.8)',
                        'rgba(0, 168, 107, 0.8)',
                        'rgba(255, 215, 0, 0.8)',
                        'rgba(220, 53, 69, 0.8)',
                        'rgba(33, 150, 243, 0.8)',
                        'rgba(156, 39, 176, 0.8)'
                    ],
                    borderColor: [
                        'rgba(10, 31, 68, 1)',
                        'rgba(0, 168, 107, 1)',
                        'rgba(255, 215, 0, 1)',
                        'rgba(220, 53, 69, 1)',
                        'rgba(33, 150, 243, 1)',
                        'rgba(156, 39, 176, 1)'
                    ],
                    borderWidth: 2
                }]
            };

            new Chart(ctx, {
                type: 'doughnut',
                data: assetData,
                options: {
                    responsive: true,
                    maintainAspectRatio: false,
                    plugins: {
                        legend: {
                            position: 'bottom',
                            labels: {
                                font: { family: "'Inter', sans-serif" },
                                padding: 20,
                                usePointStyle: true
                            }
                        }
                    }
                }
            });
        }
    </script>
</body>
</html>

