{% extends 'dashboard/base_dashboard.html' %}
{% load static %}
{% load humanize %}

{% block title %}Investment Plans{% endblock %}

{% block extra_css %}
<style>
    .plans-header {
        text-align: center;
        margin-bottom: 30px;
    }

    .plans-header h1 {
        color: var(--gold);
        margin-bottom: 10px;
    }

    .plans-header p {
        color: var(--text-secondary);
    }

    .balance-info {
        background: linear-gradient(135deg, rgba(0, 212, 170, 0.1), rgba(255, 215, 0, 0.1));
        border: 1px solid var(--border-color);
        border-radius: 15px;
        padding: 20px;
        display: flex;
        align-items: center;
        justify-content: space-between;
        margin-bottom: 25px;
    }

    .balance-info .balance-text {
        color: var(--text-secondary);
    }

    .balance-info .balance-amount {
        font-size: 1.5rem;
        font-weight: 700;
        color: var(--success);
    }

    .plans-grid {
        display: grid;
        grid-template-columns: repeat(auto-fill, minmax(350px, 1fr));
        gap: 25px;
    }

    .plan-card {
        background: var(--bg-card);
        border: 1px solid var(--border-color);
        border-radius: 20px;
        padding: 30px;
        transition: all 0.3s;
        position: relative;
        overflow: hidden;
    }

    .plan-card:hover {
        transform: translateY(-5px);
        box-shadow: 0 15px 40px rgba(255, 215, 0, 0.15);
        border-color: rgba(255, 215, 0, 0.5);
    }

    .plan-card.featured {
        border: 2px solid var(--gold);
        box-shadow: 0 10px 30px rgba(255, 215, 0, 0.2);
    }

    .featured-badge {
        position: absolute;
        top: 15px;
        right: 15px;
        background: linear-gradient(135deg, var(--gold), var(--gold-dark));
        color: var(--bg-darkest);
        padding: 6px 15px;
        border-radius: 20px;
        font-weight: 700;
        font-size: 0.75rem;
    }

    .plan-header {
        text-align: center;
        margin-bottom: 20px;
    }

    .plan-icon {
        width: 70px;
        height: 70px;
        border-radius: 50%;
        background: linear-gradient(135deg, rgba(255, 215, 0, 0.2), rgba(255, 165, 0, 0.1));
        display: flex;
        align-items: center;
        justify-content: center;
        font-size: 1.8rem;
        color: var(--gold);
        margin: 0 auto 15px;
    }

    .plan-name {
        font-size: 1.3rem;
        font-weight: 700;
        margin-bottom: 5px;
        color: var(--text-primary);
    }

    .category-badge {
        display: inline-block;
        background: rgba(255, 215, 0, 0.15);
        color: var(--gold);
        padding: 4px 12px;
        border-radius: 20px;
        font-size: 0.75rem;
        font-weight: 600;
        border: 1px solid rgba(255, 215, 0, 0.3);
    }

    .plan-roi {
        text-align: center;
        padding: 20px 0;
        border-top: 1px solid var(--border-color);
        border-bottom: 1px solid var(--border-color);
        margin: 15px 0;
    }

    .plan-roi .roi-value {
        font-size: 2.5rem;
        font-weight: 800;
        color: var(--success);
    }

    .plan-roi .roi-label {
        font-size: 0.85rem;
        color: var(--text-muted);
        display: block;
    }

    .plan-description {
        color: var(--text-secondary);
        font-size: 0.9rem;
        line-height: 1.5;
        margin-bottom: 15px;
        text-align: center;
    }

    .plan-details {
        background: rgba(255, 255, 255, 0.02);
        border-radius: 12px;
        padding: 15px;
        margin-bottom: 20px;
    }

    .detail-row {
        display: flex;
        justify-content: space-between;
        padding: 10px 0;
        border-bottom: 1px solid rgba(255, 255, 255, 0.05);
    }

    .detail-row:last-child {
        border-bottom: none;
        padding-bottom: 0;
    }

    .detail-row:first-child {
        padding-top: 0;
    }

    .detail-label {
        color: var(--text-muted);
        font-size: 0.9rem;
    }

    .detail-label i {
        color: var(--gold);
        margin-right: 8px;
    }

    .detail-value {
        color: var(--text-primary);
        font-weight: 600;
    }

    .detail-value.highlight {
        color: var(--success);
    }

    .invest-btn {
        background: linear-gradient(135deg, var(--gold), var(--gold-dark));
        border: none;
        padding: 14px 30px;
        font-size: 1rem;
        border-radius: 12px;
        color: var(--bg-darkest);
        font-weight: 700;
        width: 100%;
        cursor: pointer;
        transition: all 0.3s;
        text-decoration: none;
        display: flex;
        align-items: center;
        justify-content: center;
        gap: 8px;
    }

    .invest-btn:hover {
        transform: translateY(-2px);
        box-shadow: 0 10px 25px rgba(255, 215, 0, 0.4);
        color: var(--bg-darkest);
    }

    .no-plans-card {
        text-align: center;
        padding: 60px 30px;
        background: var(--bg-card);
        border: 1px solid var(--border-color);
        border-radius: 20px;
    }

    .no-plans-card i {
        font-size: 4rem;
        color: var(--gold);
        opacity: 0.5;
        margin-bottom: 20px;
    }

    .no-plans-card h3 {
        color: var(--text-primary);
        margin-bottom: 10px;
    }

    .no-plans-card p {
        color: var(--text-muted);
    }

    @media (max-width: 768px) {
        .plans-grid {
            grid-template-columns: 1fr;
        }

        .balance-info {
            flex-direction: column;
            text-align: center;
            gap: 10px;
        }

        .plan-roi .roi-value {
            font-size: 2rem;
        }
    }
</style>
{% endblock %}

{% block content %}
<!-- Top Bar -->
<div class="topbar">
    <div class="topbar-title">
        <h1><i class="fas fa-rocket me-2" style="color: var(--gold);"></i>Investment Plans</h1>
        <p>Choose a plan and start earning profits</p>
    </div>
    <a href="{% url 'dashboard:dashboard' %}" class="btn-outline">
        <i class="fas fa-arrow-left me-2"></i>Dashboard
    </a>
</div>

<!-- Available Balance -->
{% if user.is_authenticated %}
<div class="balance-info">
    <div>
        <span class="balance-text">Your Available Balance</span>
        <div class="balance-amount">${{ user.balance|floatformat:2|intcomma }}</div>
    </div>
    <a href="{% url 'investments:deposit' %}" class="btn-gold">
        <i class="fas fa-plus me-2"></i>Add Funds
    </a>
</div>
{% else %}
<div class="balance-info">
    <div>
        <span class="balance-text">Ready to start investing?</span>
        <div class="balance-amount" style="font-size: 1rem;">Create an account to get started</div>
    </div>
    <a href="{% url 'accounts:signup' %}" class="btn-gold">
        <i class="fas fa-user-plus me-2"></i>Sign Up
    </a>
</div>
{% endif %}

<!-- Investment Plans Grid -->
{% if plans %}
<div class="plans-grid">
    {% for plan in plans %}
    <div class="plan-card {% if plan.is_featured %}featured{% endif %}">
        {% if plan.is_featured %}
        <div class="featured-badge">
            <i class="fas fa-star me-1"></i>POPULAR
        </div>
        {% endif %}

        <div class="plan-header">
            <div class="plan-icon">
                <i class="fas {{ plan.icon|default:'fa-chart-line' }}"></i>
            </div>
            <h2 class="plan-name">{{ plan.name }}</h2>
            {% if plan.category %}
            <span class="category-badge">{{ plan.get_category_display }}</span>
            {% endif %}
        </div>

        <p class="plan-description">{{ plan.description|truncatewords:20 }}</p>

        <div class="plan-roi">
            <span class="roi-value">{{ plan.daily_roi }}%</span>
            <span class="roi-label">Daily Profit</span>
        </div>

        <div class="plan-details">
            <div class="detail-row">
                <span class="detail-label">
                    <i class="fas fa-coins"></i>Min Amount
                </span>
                <span class="detail-value">${{ plan.min_amount|floatformat:2|intcomma }}</span>
            </div>
            <div class="detail-row">
                <span class="detail-label">
                    <i class="fas fa-gem"></i>Max Amount
                </span>
                <span class="detail-value">${{ plan.max_amount|floatformat:2|intcomma }}</span>
            </div>
            <div class="detail-row">
                <span class="detail-label">
                    <i class="fas fa-clock"></i>Duration
                </span>
                <span class="detail-value">{{ plan.duration_days }} Days</span>
            </div>
            <div class="detail-row">
                <span class="detail-label">
                    <i class="fas fa-percentage"></i>Total Return
                </span>
                <span class="detail-value highlight">{{ plan.total_roi|floatformat:0 }}%</span>
            </div>
        </div>

        <a href="{% url 'investments:invest' plan_id=plan.id %}" class="invest-btn">
            <i class="fas fa-rocket"></i>Invest Now
        </a>
    </div>
    {% endfor %}
</div>
{% else %}
<div class="no-plans-card">
    <i class="fas fa-chart-line"></i>
    <h3>No Investment Plans Available</h3>
    <p>Check back soon for new investment opportunities.</p>
    <a href="{% url 'dashboard:dashboard' %}" class="btn-gold mt-3">
        <i class="fas fa-home me-2"></i>Back to Dashboard
    </a>
</div>
{% endif %}
{% endblock %}

