                        <span class="detail-label">Target Returns:</span>
                        <span class="detail-value">{{ plan.daily_roi }}%</span>
                    </div>
                    <div class="plan-detail-row">
                        <span class="detail-label">Duration:</span>
                        <span class="detail-value">{{ plan.duration_days }} days</span>
                    </div>
                    <div class="plan-detail-row">
                        <span class="detail-label">Total ROI:</span>
                        <span class="detail-value">{{ plan.total_roi }}%</span>
                    </div>
                </div>

                {% if user.is_authenticated %}
                    <a href="{% url 'investments:invest' plan.id %}" class="plan-btn">
                        <i class="fas fa-check-circle me-2"></i>Buy Shares
                    </a>
                {% else %}
                    <a href="{% url 'accounts:login' %}?next={{ request.path }}" class="plan-btn">
                        <i class="fas fa-sign-in-alt me-2"></i>Login to Invest
                    </a>
                {% endif %}
            </div>
            {% endfor %}
        </div>
        {% else %}
        <div class="no-plans">
            <i class="fas fa-info-circle fa-3x mb-3"></i>
            <h3>No plans available in this sector yet</h3>
            <p>Check back soon for new investment opportunities!</p>
        </div>
        {% endif %}

        <!-- CTA Section -->
        <div class="text-center mt-5 pt-5">
            <h3 class="text-white mb-3" style="font-size: 2rem;">Ready to Start Investing?</h3>
            <p class="text-white-50 mb-4">Join thousands of investors building wealth with Elite Wealth Capital</p>
            {% if not user.is_authenticated %}
            <a href="{% url 'accounts:signup' %}" class="btn btn-lg px-5 py-3" style="background: rgba(255,255,255,0.9); color: #000; border-radius: 50px; font-weight: 700;">
                <i class="fas fa-user-plus me-2"></i>Create Free Account
            </a>
            {% endif %}
        </div>
    </div>
</div>
{% endblock %}

{% block extra_js %}
<script src="https://unpkg.com/aos@2.3.1/dist/aos.js"></script>
<script>
    AOS.init({
        duration: 800,
        once: true,
        offset: 100,
    });
</script>
{% endblock %}

