{% extends 'dashboard/base_dashboard.html' %}
{% load static %}
{% load humanize %}

{% block title %}Dashboard{% endblock %}

{% block extra_css %}
<style>
    /* Crypto Ticker */
    .crypto-ticker-container {
        background: linear-gradient(90deg, var(--bg-dark), var(--bg-darkest));
        border: 1px solid var(--border-color);
        border-radius: 12px;
        overflow: hidden;
        margin-bottom: 20px;
    }

    .crypto-ticker {
        display: flex;
        animation: ticker-scroll 30s linear infinite;
        padding: 12px 0;
    }

    .crypto-ticker:hover {
        animation-play-state: paused;
    }

    @keyframes ticker-scroll {
        0% { transform: translateX(0); }
        100% { transform: translateX(-50%); }
    }

    .ticker-item {
        display: flex;
        align-items: center;
        padding: 0 25px;
        white-space: nowrap;
        border-right: 1px solid var(--border-color);
    }

    .ticker-item img {
        width: 24px;
        height: 24px;
        margin-right: 10px;
        border-radius: 50%;
    }

    .ticker-symbol {
        font-weight: 600;
        margin-right: 8px;
        color: var(--text-primary);
    }

    .ticker-price {
        color: var(--text-secondary);
        margin-right: 8px;
    }

    .ticker-change {
        font-size: 0.85rem;
        padding: 2px 8px;
        border-radius: 4px;
    }

    .ticker-change.up {
        background: rgba(0, 212, 170, 0.2);
        color: var(--success);
    }

    .ticker-change.down {
        background: rgba(255, 71, 87, 0.2);
        color: var(--error);
    }

    /* Welcome Header */
    .welcome-header {
        display: flex;
        align-items: center;
        justify-content: space-between;
        background: var(--bg-card);
        border: 1px solid var(--border-color);
        border-radius: 20px;
        padding: 25px 30px;
        margin-bottom: 25px;
    }

    .welcome-left {
        display: flex;
        align-items: center;
        gap: 20px;
    }

    .user-avatar-large {
        width: 70px;
        height: 70px;
        border-radius: 50%;
        background: linear-gradient(135deg, var(--gold), var(--gold-dark));
        display: flex;
        align-items: center;
        justify-content: center;
        font-size: 1.8rem;
        color: var(--bg-darkest);
        font-weight: 700;
        border: 3px solid var(--gold);
        overflow: hidden;
    }

    .user-avatar-large img {
        width: 100%;
        height: 100%;
        object-fit: cover;
    }

    .welcome-text h1 {
        font-size: 1.5rem;
        font-weight: 700;
        margin: 0 0 5px 0;
    }

    .welcome-text p {
        color: var(--text-muted);
        margin: 0;
    }

    .welcome-right {
        display: flex;
        align-items: center;
        gap: 15px;
    }

    .notification-btn {
        position: relative;
        width: 50px;
        height: 50px;
        border-radius: 15px;
        background: var(--bg-card);
        border: 1px solid var(--border-color);
        color: var(--text-secondary);
        display: flex;
        align-items: center;
        justify-content: center;
        font-size: 1.3rem;
        cursor: pointer;
        transition: all 0.3s;
        text-decoration: none;
    }

    .notification-btn:hover {
        background: var(--gold);
        color: var(--bg-darkest);
        border-color: var(--gold);
    }

    .notification-badge {
        position: absolute;
        top: -5px;
        right: -5px;
        background: var(--error);
        color: #fff;
        font-size: 0.7rem;
        font-weight: 700;
        min-width: 20px;
        height: 20px;
        border-radius: 10px;
        display: flex;
        align-items: center;
        justify-content: center;
        padding: 0 5px;
    }

    /* Stats Grid */
    .stats-grid {
        display: grid;
        grid-template-columns: repeat(4, 1fr);
        gap: 20px;
        margin-bottom: 25px;
    }

    .stat-card {
        background: var(--bg-card);
        border: 1px solid var(--border-color);
        border-radius: 20px;
        padding: 25px;
        backdrop-filter: blur(10px);
        position: relative;
        overflow: hidden;
        text-align: center;
    }

    .stat-card::before {
        content: '';
        position: absolute;
        top: 0;
        right: 0;
        width: 100px;
        height: 100px;
        background: linear-gradient(135deg, rgba(255, 215, 0, 0.1), transparent);
        border-radius: 0 0 0 100%;
    }

    .stat-icon {
        width: 60px;
        height: 60px;
        border-radius: 50%;
        display: flex;
        align-items: center;
        justify-content: center;
        font-size: 1.5rem;
        margin: 0 auto 15px;
    }

    .stat-icon.balance { background: rgba(0, 212, 170, 0.2); color: var(--success); }
    .stat-icon.invested { background: rgba(255, 215, 0, 0.2); color: var(--gold); }
    .stat-icon.profit { background: rgba(0, 212, 170, 0.2); color: var(--success); }
    .stat-icon.withdrawn { background: rgba(255, 71, 87, 0.2); color: var(--error); }

    .stat-label {
        color: var(--text-muted);
        font-size: 0.85rem;
        margin-bottom: 8px;
    }

    .stat-value {
        font-size: 1.6rem;
        font-weight: 700;
    }

    .stat-value.success { color: var(--success); }
    .stat-value.gold { color: var(--gold); }

    /* Quick Actions */
    .quick-actions {
        display: grid;
        grid-template-columns: repeat(4, 1fr);
        gap: 15px;
        margin-bottom: 25px;
    }

    .action-btn {
        background: var(--bg-card);
        border: 1px solid var(--border-color);
        border-radius: 15px;
        padding: 20px;
        text-align: center;
        text-decoration: none;
        color: var(--text-primary);
        transition: all 0.3s ease;
    }

    .action-btn:hover {
        background: linear-gradient(135deg, var(--gold), var(--gold-dark));
        color: var(--bg-darkest);
        border-color: var(--gold);
        transform: translateY(-3px);
    }

    .action-btn.primary {
        background: linear-gradient(135deg, var(--gold), var(--gold-dark));
        color: var(--bg-darkest);
        border-color: var(--gold);
    }

    .action-btn.primary:hover {
        box-shadow: 0 10px 30px rgba(255, 215, 0, 0.4);
    }

    .action-btn i {
        font-size: 1.5rem;
        display: block;
        margin-bottom: 10px;
    }

    .action-btn span {
        font-weight: 600;
        font-size: 0.9rem;
    }

    /* Content Grid */
    .content-grid {
        display: grid;
        grid-template-columns: 2fr 1fr;
        gap: 25px;
    }

    /* Investments List */
    .investment-item {
        display: flex;
        align-items: center;
        padding: 15px;
        background: rgba(255, 255, 255, 0.02);
        border-radius: 12px;
        margin-bottom: 12px;
        transition: all 0.3s ease;
    }

    .investment-item:hover {
        background: rgba(255, 255, 255, 0.05);
    }

    .investment-icon {
        width: 45px;
        height: 45px;
        border-radius: 12px;
        background: linear-gradient(135deg, var(--gold), var(--gold-dark));
        display: flex;
        align-items: center;
        justify-content: center;
        color: var(--bg-darkest);
        font-size: 1.1rem;
        margin-right: 15px;
    }

    .investment-info h4 {
        font-size: 0.95rem;
        font-weight: 600;
        margin-bottom: 3px;
    }

    .investment-info p {
        color: var(--text-muted);
        font-size: 0.8rem;
        margin: 0;
    }

    .investment-amount {
        margin-left: auto;
        text-align: right;
    }

    .investment-amount .amount {
        font-weight: 600;
        color: var(--success);
    }

    .investment-amount .status {
        font-size: 0.75rem;
        padding: 3px 10px;
        border-radius: 20px;
        background: rgba(0, 212, 170, 0.2);
        color: var(--success);
    }

    /* Account Status Card */
    .account-status-card {
        background: var(--bg-card);
        border: 1px solid var(--border-color);
        border-radius: 20px;
        padding: 25px;
    }

    .status-row {
        display: flex;
        align-items: center;
        justify-content: space-between;
        padding: 15px 0;
        border-bottom: 1px solid rgba(255, 255, 255, 0.05);
    }

    .status-row:last-child {
        border-bottom: none;
        padding-bottom: 0;
    }

    .status-row:first-child {
        padding-top: 0;
    }

    .status-info {
        display: flex;
        align-items: center;
        gap: 12px;
    }

    .status-icon {
        width: 40px;
        height: 40px;
        border-radius: 10px;
        display: flex;
        align-items: center;
        justify-content: center;
    }

    .status-icon.verified { background: rgba(0, 212, 170, 0.2); color: var(--success); }
    .status-icon.pending { background: rgba(255, 165, 2, 0.2); color: var(--warning); }
    .status-icon.unverified { background: rgba(255, 71, 87, 0.2); color: var(--error); }
    .status-icon.gold { background: rgba(255, 215, 0, 0.2); color: var(--gold); }

    .status-label {
        color: var(--text-muted);
        font-size: 0.8rem;
    }

    .status-value {
        font-weight: 600;
    }

    .status-badge {
        padding: 5px 12px;
        border-radius: 20px;
        font-size: 0.8rem;
        font-weight: 500;
    }

    .status-badge.verified { background: rgba(0, 212, 170, 0.2); color: var(--success); }
    .status-badge.pending { background: rgba(255, 165, 2, 0.2); color: var(--warning); }
    .status-badge.unverified { background: rgba(255, 71, 87, 0.2); color: var(--error); }

    /* Section Header */
    .section-header {
        display: flex;
        justify-content: space-between;
        align-items: center;
        margin-bottom: 20px;
    }

    .section-header h3 {
        font-size: 1.1rem;
        font-weight: 600;
        margin: 0;
    }

    .section-header a {
        color: var(--gold);
        font-size: 0.85rem;
        text-decoration: none;
    }

    .section-header a:hover {
        text-decoration: underline;
    }

    /* Empty State */
    .empty-state {
        text-align: center;
        padding: 40px 20px;
        color: var(--text-muted);
    }

    .empty-state i {
        font-size: 3rem;
        margin-bottom: 15px;
        opacity: 0.5;
    }

    /* Responsive */
    @media (max-width: 1200px) {
        .stats-grid {
            grid-template-columns: repeat(2, 1fr);
        }
    }

    @media (max-width: 991px) {
        .content-grid {
            grid-template-columns: 1fr;
        }

        .quick-actions {
            grid-template-columns: repeat(2, 1fr);
        }

        .welcome-header {
            flex-direction: column;
            text-align: center;
            gap: 20px;
        }

        .welcome-left {
            flex-direction: column;
        }
    }

    @media (max-width: 576px) {
        .stats-grid {
            grid-template-columns: repeat(2, 1fr);
        }

        .quick-actions {
            grid-template-columns: repeat(2, 1fr);
        }

        .stat-card {
            padding: 18px 15px;
        }

        .stat-value {
            font-size: 1.3rem;
        }
    }
</style>
{% endblock %}

