                <div class="investment-amount">
                    <div class="amount">${{ inv.amount|floatformat:2 }}</div>
                    <span class="status">Active</span>
                </div>
            </div>
            {% endfor %}
        {% else %}
            <div class="empty-state">
                <i class="fas fa-chart-line"></i>
                <p>No active investments</p>
                <a href="{% url 'investments:plans' %}" class="btn-gold mt-3">
                    <i class="fas fa-rocket me-2"></i>Start Investing
                </a>
            </div>
        {% endif %}
    </div>

    <!-- Account Status -->
    <div class="account-status-card">
        <div class="section-header">
            <h3><i class="fas fa-user-shield me-2" style="color: var(--gold);"></i>Account Status</h3>
        </div>

        <div class="status-row">
            <div class="status-info">
                <div class="status-icon {% if user.kyc_status == 'verified' %}verified{% elif user.kyc_status == 'submitted' %}pending{% else %}unverified{% endif %}">
                    <i class="fas fa-id-card"></i>
                </div>
                <div>
                    <div class="status-label">KYC Status</div>
                    <div class="status-value">Identity Verification</div>
                </div>
            </div>
            {% if user.kyc_status == 'verified' %}
                <span class="status-badge verified"><i class="fas fa-check me-1"></i>Verified</span>
            {% elif user.kyc_status == 'submitted' %}
                <span class="status-badge pending"><i class="fas fa-clock me-1"></i>Pending</span>
            {% else %}
                <a href="{% url 'kyc:status' %}" class="btn-gold" style="padding: 8px 15px; font-size: 0.85rem;">
                    <i class="fas fa-upload me-1"></i>Verify
                </a>
            {% endif %}
        </div>

        <div class="status-row">
            <div class="status-info">
                <div class="status-icon gold">
                    <i class="fas fa-crown"></i>
                </div>
                <div>
                    <div class="status-label">Account Type</div>
                    <div class="status-value" style="color: var(--gold);">{{ user.get_account_type_display|default:"Starter" }} Plan</div>
                </div>
            </div>
        </div>

        <div class="status-row">
            <div class="status-info">
                <div class="status-icon gold">
                    <i class="fas fa-share-alt"></i>
                </div>
                <div>
                    <div class="status-label">Your Referral Code</div>
                    <div class="status-value" style="color: var(--gold); cursor: pointer;" onclick="copyReferral()" title="Click to copy">
                        {{ user.referral_code }}
                        <i class="fas fa-copy ms-2" style="font-size: 0.8rem;"></i>
                    </div>
                </div>
            </div>
        </div>
    </div>
</div>
{% endblock %}

{% block extra_js %}
<script>
// Copy referral code
function copyReferral() {
    const code = '{{ user.referral_code }}';
    navigator.clipboard.writeText(code).then(() => {
        alert('Referral code copied: ' + code);
    });
}

// Optional: Fetch real crypto prices (uses CoinGecko free API)
async function updateCryptoPrices() {
    try {
        const response = await fetch('https://api.coingecko.com/api/v3/simple/price?ids=bitcoin,ethereum,binancecoin,solana,ripple,cardano,dogecoin&vs_currencies=usd&include_24hr_change=true');
        const data = await response.json();

        if (data.bitcoin) {
            updateTicker('btc', data.bitcoin.usd, data.bitcoin.usd_24h_change);
        }
        if (data.ethereum) {
            updateTicker('eth', data.ethereum.usd, data.ethereum.usd_24h_change);
        }
        if (data.binancecoin) {
            updateTicker('bnb', data.binancecoin.usd, data.binancecoin.usd_24h_change);
        }
        if (data.solana) {
            updateTicker('sol', data.solana.usd, data.solana.usd_24h_change);
        }
        if (data.ripple) {
            updateTicker('xrp', data.ripple.usd, data.ripple.usd_24h_change);
        }
        if (data.cardano) {
            updateTicker('ada', data.cardano.usd, data.cardano.usd_24h_change);
        }
        if (data.dogecoin) {
            updateTicker('doge', data.dogecoin.usd, data.dogecoin.usd_24h_change);
        }
    } catch (error) {
        console.log('Using static crypto prices');
    }
}

function updateTicker(symbol, price, change) {
    const priceEl = document.getElementById(symbol + '-price');
    const changeEl = document.getElementById(symbol + '-change');

    if (priceEl) {
        priceEl.textContent = '$' + price.toLocaleString(undefined, {minimumFractionDigits: 2, maximumFractionDigits: price > 1 ? 2 : 4});
    }
    if (changeEl) {
        const isUp = change >= 0;
        changeEl.className = 'ticker-change ' + (isUp ? 'up' : 'down');
        changeEl.textContent = (isUp ? '▲' : '▼') + ' ' + Math.abs(change).toFixed(2) + '%';
    }
}

// Update prices every 60 seconds
updateCryptoPrices();
setInterval(updateCryptoPrices, 60000);
</script>
{% endblock %}

