    <link href="https://cdn.jsdelivr.net/npm/bootstrap@5.3.0/dist/css/bootstrap.min.css" rel="stylesheet">

    <style>
        :root {
            --bg-darkest: #050B1A;
            --bg-dark: #0A1F44;
            --bg-card: rgba(255, 255, 255, 0.05);
            --gold: #FFD700;
            --gold-dark: #FFA500;
            --text-primary: #FFFFFF;
            --text-secondary: rgba(255, 255, 255, 0.7);
            --text-muted: rgba(255, 255, 255, 0.5);
            --success: #00D4AA;
            --error: #FF4757;
            --warning: #FFA502;
            --border-color: rgba(255, 215, 0, 0.2);
            --sidebar-width: 280px;
        }

        * {
            margin: 0;
            padding: 0;
            box-sizing: border-box;
        }

        body {
            font-family: 'Inter', sans-serif;
            background: var(--bg-darkest);
            color: var(--text-primary);
            min-height: 100vh;
        }

        /* Sidebar */
        .sidebar {
            position: fixed;
            left: 0;
            top: 0;
            width: var(--sidebar-width);
            height: 100vh;
            background: linear-gradient(180deg, var(--bg-dark) 0%, var(--bg-darkest) 100%);
            border-right: 1px solid var(--border-color);
            z-index: 1000;
            overflow-y: auto;
            transition: transform 0.3s ease;
        }

        .sidebar-header {
            padding: 25px 20px;
            border-bottom: 1px solid var(--border-color);
            text-align: center;
        }

        .sidebar-logo {
            height: 45px;
            margin-bottom: 10px;
        }

        .sidebar-brand {
            color: var(--gold);
            font-weight: 700;
            font-size: 1.1rem;
        }

        .sidebar-user {
            padding: 20px;
            background: var(--bg-card);
            margin: 15px;
            border-radius: 15px;
            text-align: center;
        }

        .user-avatar {
            width: 60px;
            height: 60px;
            border-radius: 50%;
            background: linear-gradient(135deg, var(--gold), var(--gold-dark));
            display: flex;
            align-items: center;
            justify-content: center;
            margin: 0 auto 10px;
            font-size: 1.5rem;
            color: var(--bg-darkest);
            font-weight: 700;
        }

        .user-name {
            font-weight: 600;
            margin-bottom: 5px;
        }

        .user-balance {
            color: var(--success);
            font-size: 1.25rem;
            font-weight: 700;
        }

        .sidebar-nav {
            padding: 15px 0;
        }

        .nav-section {
            padding: 10px 20px 5px;
            color: var(--text-muted);
            font-size: 0.75rem;
            text-transform: uppercase;
            letter-spacing: 1px;
            font-weight: 600;
        }

        .nav-item {
            display: block;
            padding: 12px 20px;
            color: var(--text-secondary);
            text-decoration: none;
            transition: all 0.3s ease;
            border-left: 3px solid transparent;
        }

        .nav-item:hover, .nav-item.active {
            background: var(--bg-card);
            color: var(--gold);
            border-left-color: var(--gold);
        }

        .nav-item i {
            width: 24px;
            margin-right: 12px;
            text-align: center;
        }

        .nav-item .badge {
            background: var(--error);
            color: #fff;
            font-size: 0.7rem;
            padding: 3px 8px;
            border-radius: 10px;
            margin-left: auto;
        }

        /* Main Content */
        .main-content {
            margin-left: var(--sidebar-width);
            min-height: 100vh;
            padding: 20px;
        }

